from __future__ import annotations

from typing import Any, AsyncIterator, Callable, Iterable, List, Optional, Sequence, TypeVar

T_Retval = TypeVar("T_Retval")


def create_cancel_scope(*, shield: bool = False, deadline: Optional[float] = None) -> Any:
    """
    Create and return a new cancel scope.

    A cancel scope is an object that can be used to cancel one or more tasks that
    are running within that scope. The `shield` parameter indicates whether the scope
    should be shielded from external cancellation. The `deadline` parameter, if
    provided, is a clock value (in seconds) after which the scope is considered
    cancelled.

    Note: This function is a placeholder and its concrete behavior depends on the
    asynchronous backend in use.
    """
    raise NotImplementedError("create_cancel_scope must be provided by an async backend")


def create_task_group() -> Any:
    """
    Create and return a new task group.

    A task group is a context manager / object that allows starting and managing a
    collection of related tasks. Tasks started in the group are monitored, and the
    group can be awaited to ensure all tasks have completed (or to propagate errors).

    Note: This function is a placeholder and should be implemented by the chosen
    asynchronous backend.
    """
    raise NotImplementedError("create_task_group must be provided by an async backend")


def create_event() -> Any:
    """
    Create and return a new event object.

    The event provides a simple synchronization primitive with methods to wait for
    it to be set and to set/clear it. The precise interface depends on the backend.

    Note: This function is a placeholder; use a concrete backend implementation.
    """
    raise NotImplementedError("create_event must be provided by an async backend")


def create_lock() -> Any:
    """
    Create and return a new lock object.

    The lock can be used to provide mutual exclusion between tasks. The exact
    behavior and API are backend-specific.

    Note: This is a placeholder; use the backend's lock implementation.
    """
    raise NotImplementedError("create_lock must be provided by an async backend")


def create_semaphore(value: int = 1) -> Any:
    """
    Create and return a new semaphore object with the given initial value.

    Semaphores are used to limit concurrent access to a resource. The `value`
    parameter specifies the initial number of available permits.

    Note: Backend implementations should provide the concrete semaphore type.
    """
    raise NotImplementedError("create_semaphore must be provided by an async backend")


def create_capacity_limiter(total_tokens: int) -> Any:
    """
    Create and return a capacity limiter object.

    A capacity limiter is a synchronization primitive that allows controlling the
    total amount of a resource that can be acquired at any time. The `total_tokens`
    argument defines the total capacity.

    Note: This function is a placeholder and must be implemented by the backend.
    """
    raise NotImplementedError("create_capacity_limiter must be provided by an async backend")


def check_cancelled() -> None:
    """
    Check whether the current cancel scope or task group has been cancelled.

    If the current context has been cancelled, this function should raise the
    appropriate cancellation exception for the backend. If not cancelled, it should
    simply return.

    Note: The concrete exception type is backend-specific.
    """
    raise NotImplementedError("check_cancelled must be provided by an async backend")


def run_async_from_thread(
    func: Callable[..., T_Retval],
    /,
    *args: Any,
    cancellable: bool = False,
    enable_ki_protection: bool = True,
) -> T_Retval:
    """
    Run an async-capable callable from a non-async thread and wait for its result.

    This is intended for calling into an asynchronous runtime from a synchronous
    thread. The callable `func` may be a coroutine function or a function that
    returns an awaitable. The `cancellable` flag indicates whether the call should
    be cancellable from the synchronous caller. The `enable_ki_protection` flag
    can be used to configure how KeyboardInterrupt (SIGINT) is handled.

    Note: Concrete behavior depends on the asynchronous backend; this is a stub.
    """
    raise NotImplementedError("run_async_from_thread must be implemented by the backend")


def run_sync_from_thread(
    func: Callable[..., T_Retval],
    /,
    *args: Any,
    limit_concurrency: Optional[bool] = None,
) -> T_Retval:
    """
    Run a synchronous callable from within an asynchronous thread and return its result.

    This helper is useful when you are in an async context but need to execute a
    blocking synchronous function without blocking the entire event loop. The
    `limit_concurrency` parameter, if provided, can be used by the backend to decide
    whether to limit concurrent synchronous calls.

    Note: This function is a placeholder and must be provided by the backend.
    """
    raise NotImplementedError("run_sync_from_thread must be implemented by the backend")


def setup_process_pool_exit_at_shutdown(pool: Any) -> None:
    """
    Configure a process pool to be cleanly shut down when the program exits.

    This function ensures that worker processes in a given process pool are
    terminated or joined at interpreter shutdown, avoiding orphaned processes.

    The exact pool type and management semantics are backend-specific.
    """
    raise NotImplementedError("setup_process_pool_exit_at_shutdown must be implemented by the backend")


def create_tcp_listener(
    host: str,
    port: int,
    *,
    ssl: Optional[Any] = None,
    backlog: int = 100,
) -> Any:
    """
    Create and return a TCP listener bound to the given host and port.

    The returned object depends on the backend and typically supports an async
    iterator or `accept()` method to accept incoming connections. The `ssl`
    parameter may be used to wrap connections with TLS. The `backlog` parameter
    specifies the listen backlog.

    Note: Backend-specific implementation required.
    """
    raise NotImplementedError("create_tcp_listener must be implemented by the backend")


def create_unix_listener(path: str, *, mode: int = 0o777, backlog: int = 100) -> Any:
    """
    Create and return a UNIX domain socket listener bound to the given path.

    The returned listener object will accept connections on the UNIX socket
    at `path`. The `mode` parameter can set filesystem permissions for the socket
    file. Behavior is platform-dependent.

    Note: Not all backends or platforms support UNIX domain sockets.
    """
    raise NotImplementedError("create_unix_listener must be implemented by the backend")


def notify_closing(obj: Any) -> None:
    """
    Notify a stream or listener that it is closing.

    This hook can be used to awaken awaiters and unblock pending operations when
    a resource is being closed. The exact semantics depend on the resource type.

    Note: This function is a generic helper; backends may override with optimized
    implementations.
    """
    raise NotImplementedError("notify_closing must be implemented by the backend")


def current_default_thread_limiter() -> Any:
    """
    Return the current default thread limiter.

    This object can be used to limit concurrency for operations that run on
    worker threads (for example, via a thread pool). The concrete limiter type
    is backend-specific.

    Note: This is a placeholder and should be provided by the runtime environment.
    """
    raise NotImplementedError("current_default_thread_limiter must be provided by the backend")


async def open_signal_receiver(*signals: int) -> AsyncIterator[int]:
    """
    Open an asynchronous signal receiver that yields signal numbers as they arrive.

    This async iterator yields integers corresponding to the received signals. It
    should be used in an async for loop. The `signals` argument is a sequence of
    signal numbers (as integers) to listen for; if none are provided, a sensible
    default may be used (backend-dependent).

    Note: Implementations must be careful to interact correctly with the event
    loop's signal handling facilities and the platform's restrictions.
    """
    raise NotImplementedError("open_signal_receiver must be implemented by the backend")


def get_current_task() -> Optional[Any]:
    """
    Return an object representing the currently running task, or None if there is none.

    The return value is backend-specific but typically allows inspection of task
    properties (such as name, status, or cancellation state). In synchronous
    contexts this may return None.
    """
    raise NotImplementedError("get_current_task must be implemented by the backend")


def get_running_tasks() -> List[Any]:
    """
    Return a list of currently running tasks for the current context or backend.

    Each item in the list is a task-like object provided by the backend. The
    exact contents of the objects are backend-specific.
    """
    raise NotImplementedError("get_running_tasks must be implemented by the backend")


def create_test_runner(
    entrypoint: Callable[..., Any],
    *,
    backend_name: Optional[str] = None,
    backend_options: Optional[dict] = None,
) -> Any:
    """
    Create and return a test runner for running async tests.

    The `entrypoint` is a callable that will be executed within the test runner.
    The `backend_name` and `backend_options` arguments can be used to select and
    configure the async backend to run tests under.

    The returned test runner is backend-specific and must support the operations
    required by the test framework in use.
    """
    raise NotImplementedError("create_test_runner must be implemented by the backend")